SELECT 
  FROM er.tn_er_fuel_smry s
 WHERE s.er_id        = #{erId}
   AND s.fuel_type_cd = #{fuelTypeCd}
   AND NOW() BETWEEN s.use_bgng_dt AND s.use_end_dt

SELECT CASE WHEN COUNT(*) > 0 THEN TRUE ELSE FALSE END
  FROM er.tn_er_fuel_smry
 WHERE er_id        = #{erId}
   AND fuel_type_cd = #{fuelTypeCd}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

mapper.update:
UPDATE er.tn_er_fuel_smry
   SET ttl_fuel_wght    = #{ttlFuelWght},
       ttl_co2_emsn     = #{ttlCo2Emsn},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{lastChgUserId}
 WHERE er_id        = #{erId}
   AND fuel_type_cd = #{fuelTypeCd}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE er.tn_er_fuel_smry
   SET use_end_dt        = NOW() - INTERVAL '1 minute',
       last_chg_dt       = NOW(),
       last_chg_user_id  = #{userId}
 WHERE er_id        = #{erId}
   AND fuel_type_cd = #{fuelTypeCd}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
